salesforce:create.salesforce:records:
#[[{
                    UUID__c: vars.categoryId,
                    Name: payload.name,
                    (Description__c: payload.description) if (payload.description != null)
                }]]

ee:message.ee:set-payload:
%dw 2.0
output application/json

var item = payload[0]
---
if (sizeOf(payload) == 0)
    {message: "Resource not found"}
else
{
    id: item.UUID__c,
    name: item.Name,
    description: item.Description__c
}

salesforce:upsert.salesforce:records:
#[[{
                    UUID__c: vars.id,
                    (Name: payload.name) if (payload.name?),
                    (Description__c: payload.description) if (payload.description != null)
                }]]

ee:message.ee:set-payload:
%dw 2.0
output application/json

var paging = {
    limit: attributes.queryParams.limit default 25,
    offset: attributes.queryParams.offset default 0
}
var results = payload map {
    id: $.UUID__c,
    name: $.Name,
    description: $.Description__c
}
---
{
    paging: paging,
    results: results
}
